import functools

def my_decorator(func):
    @functools.wraps(func)     # copies name, docstring, etc. from func to wrapper
    def wrapper(*args, **kwargs):
        print("Before")
        result = func(*args, **kwargs)
        print("After")
        return result
    return wrapper

@my_decorator
def greet(name):
    """Greets a person by name."""
    print(f"Hello, {name}!")

print(greet.__name__)   # 'greet'  ✓
print(greet.__doc__)    # 'Greets a person by name.'  ✓

import functools
import time

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        end = time.perf_counter()
        print(f"{func.__name__} ran in {end - start:.4f}s")
        return result
    return wrapper

@timer
def slow_computation(n):
    return sum(range(n))

slow_computation(10_000_000)
# slow_computation ran in 0.2341s

import functools

def retry(max_attempts=3, exceptions=(Exception,)):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt == max_attempts:
                        raise
                    print(f"Attempt {attempt} failed: {e}. Retrying...")
        return wrapper
    return decorator

@retry(max_attempts=4, exceptions=(ConnectionError, TimeoutError))
def call_llm_api(prompt):
    # simulate a flaky API call
    import random
    if random.random() < 0.5:
        raise ConnectionError("API unreachable")
    return f"Response to: {prompt}"

result = call_llm_api("Summarize this document")

import functools

class CallCounter:
    def __init__(self, func):
        functools.update_wrapper(self, func)
        self.func = func
        self.count = 0

    def __call__(self, *args, **kwargs):
        self.count += 1
        print(f"Call #{self.count} to {self.func.__name__}")
        return self.func(*args, **kwargs)

@CallCounter
def generate_text(prompt):
    return f"Generated: {prompt}"

generate_text("Hello")   # Call #1 to generate_text
generate_text("World")   # Call #2 to generate_text
print(generate_text.count)  # 2

