# Wrong — wrapper breaks for any function with arguments
def my_decorator(func):
    def wrapper():
        return func()
    return wrapper

# Right
def my_decorator(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

# Wrong — decorated function silently returns None
def log(func):
    def wrapper(*args, **kwargs):
        func(*args, **kwargs)   # result is discarded!
    return wrapper

# Right
def log(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        return result           # always return
    return wrapper

@my_decorator()   # Wrong if decorator doesn't take arguments
def func():
    pass

# Dangerous — swallows all errors silently
def safe(func):
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception:
            pass   # ← never do this

